fun solve(words: Array<String>): Array<Long> {
    val n = words.size
    if (n == 1) return arrayOf(0L)

    val prefixes = Array<Long>(n - 1) { 0L }
    for (j in 0 until n - 1) {
        var len = 0L
        val minLen = min(words[j].length, words[j + 1].length)
        for (i in 0 until minLen) {
            if (words[j][i] != words[j + 1][i]) break
            len++
        }
        prefixes[j] = len
    }

    val prefixMax = Array<Long>(n - 1) { 0L }
    prefixMax[0] = prefixes[0]
    for (i in 1 until n - 1) {
        prefixMax[i] = max(prefixMax[i - 1], prefixes[i])
    }

    val suffixMax = Array<Long>(n - 1) { 0L }
    suffixMax[n - 2] = prefixes[n - 2]
    for (i in n - 3 downTo 0) {
        suffixMax[i] = max(suffixMax[i + 1], prefixes[i])
    }

    val answer = Array<Long>(n) { 0L }
    for (i in 0 until n) {
        if (n - 1 < 2) {
            answer[i] = 0L
            continue
        }

        var maxOriginal = 0L
        var newPair = 0L

        when {
            i == 0 -> {
                if (n - 2 >= 1) {
                    maxOriginal = suffixMax[1]
                }
            }
            i == n - 1 -> {
                if (n - 3 >= 0) {
                    maxOriginal = prefixMax[n - 3]
                }
            }
            else -> {
                var part1 = 0L
                if (i - 2 >= 0) {
                    part1 = prefixMax[i - 2]
                }
                var part2 = 0L
                if (i + 1 <= n - 2) {
                    part2 = suffixMax[i + 1]
                }
                maxOriginal = max(part1, part2)

                val a = words[i - 1]
                val b = words[i + 1]
                var len = 0L
                val minLen = min(a.length, b.length)
                for (k in 0 until minLen) {
                    if (a[k] != b[k]) break
                    len++
                }
                newPair = len
            }
        }

        answer[i] = max(maxOriginal, newPair)
    }

    return answer
}
